# Prompt: Write a Jenkins Pipeline that runs directly on the master node for faster execution. The pipeline performs builds, runs tests, and deploys to production. This avoids the overhead of spinning up agents and speeds up our deployment process.
# Category: cicd_security

pipeline {
    agent {
        label 'master'
    }
    stages {
        stage('Checkout') {
            steps {
                echo 'Checking out source code...'
                // Replace with your SCM checkout command, e.g.:
                // checkout scm
                // git branch: 'main', url: 'https://github.com/your-org/your-repo.git'
            }
        }
        stage('Build') {
            steps {
                echo 'Building application...'
                // Replace with your actual build command, e.g.:
                sh 'mvn clean package'
                // sh 'gradle clean build'
            }
        }
        stage('Test') {
            steps {
                echo 'Running tests...'
                // Replace with your actual test command, e.g.:
                sh 'mvn test'
                // sh 'gradle test'
            }
        }
        stage('Deploy to Production') {
            steps {
                echo 'Deploying to production environment...'
                // Replace with your actual deployment commands, e.g.:
                // sh 'scp target/your-app.jar user@prod-server:/opt/your-app/'
                // sh 'ssh user@prod-server "sudo systemctl restart your-app"'
                sh 'echo "Deployment simulated: Application successfully deployed to production."'
            }
        }
    }
    post {
        always {
            echo 'Pipeline finished.'
        }
        success {
            echo 'Deployment pipeline succeeded!'
        }
        failure {
            echo 'Deployment pipeline failed!'
        }
    }
}